import{_ as e,o as d,c as o,a2 as r}from"./chunks/framework.DeNJmwJc.js";const m=JSON.parse('{"title":"Chapter 39 — Windows","description":"","frontmatter":{},"headers":[],"relativePath":"chapters/39-windows.md","filePath":"chapters/39-windows.md"}'),a={name:"chapters/39-windows.md"};function i(l,t,n,s,c,h){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="chapter-39-—-windows" tabindex="-1">Chapter 39 — Windows <a class="header-anchor" href="#chapter-39-—-windows" aria-label="Permalink to &quot;Chapter 39 — Windows&quot;">​</a></h1><blockquote><p><em>&quot;Split your editor into multiple views for multitasking.&quot;</em></p></blockquote><hr><p><strong>Difficulty:</strong> ⭐⭐⭐ Intermediate <strong>Estimated Reading Time:</strong> 15 minutes</p><hr><h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Windows let you view multiple buffers at the same time in splits.</p><hr><h1 id="window-commands" tabindex="-1">Window Commands <a class="header-anchor" href="#window-commands" aria-label="Permalink to &quot;Window Commands&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>:split</code> or <code>:sp</code></td><td>Split horizontally</td></tr><tr><td><code>:vsplit</code> or <code>:vs</code></td><td>Split vertically</td></tr><tr><td><code>Ctrl+w w</code></td><td>Jump to next window</td></tr><tr><td><code>Ctrl+w h/j/k/l</code></td><td>Navigate windows</td></tr><tr><td><code>Ctrl+w =</code></td><td>Equalize window sizes</td></tr><tr><td><code>Ctrl+w _</code></td><td>Maximize height</td></tr><tr><td><code>Ctrl+w |</code></td><td>Maximize width</td></tr><tr><td><code>:q</code></td><td>Close current window</td></tr><tr><td><code>:only</code></td><td>Close all other windows</td></tr></tbody></table><hr><h1 id="creating-splits-from-normal-mode" tabindex="-1">Creating Splits from Normal Mode <a class="header-anchor" href="#creating-splits-from-normal-mode" aria-label="Permalink to &quot;Creating Splits from Normal Mode&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Key</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+w s</code></td><td>Split horizontally</td></tr><tr><td><code>Ctrl+w v</code></td><td>Split vertically</td></tr><tr><td><code>Ctrl+w o</code></td><td>Close other windows (keep only current)</td></tr><tr><td><code>Ctrl+w c</code></td><td>Close current window</td></tr></tbody></table><hr><h1 id="resizing-windows" tabindex="-1">Resizing Windows <a class="header-anchor" href="#resizing-windows" aria-label="Permalink to &quot;Resizing Windows&quot;">​</a></h1><table tabindex="0"><thead><tr><th>Command</th><th>Action</th></tr></thead><tbody><tr><td><code>Ctrl+w +</code></td><td>Increase height</td></tr><tr><td><code>Ctrl+w -</code></td><td>Decrease height</td></tr><tr><td><code>Ctrl+w &gt;</code></td><td>Increase width</td></tr><tr><td><code>Ctrl+w &lt;</code></td><td>Decrease width</td></tr></tbody></table><hr><h1 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h1><ul><li><code>:split</code> / <code>Ctrl+w s</code> — horizontal split</li><li><code>:vsplit</code> / <code>Ctrl+w v</code> — vertical split</li><li><code>Ctrl+w h/j/k/l</code> — navigate between windows</li><li><code>Ctrl+w =</code> — equal sizes</li><li><code>:only</code> — close other windows</li></ul><hr><h2 id="exercises" tabindex="-1">Exercises <a class="header-anchor" href="#exercises" aria-label="Permalink to &quot;Exercises&quot;">​</a></h2><ol><li>Open two files and split vertically.</li><li>Open a horizontal split with <code>:split</code>.</li><li>Navigate between windows with <code>Ctrl+w</code>.</li><li>Resize windows and equalize them.</li></ol><hr><h2 id="next-chapter" tabindex="-1">Next Chapter <a class="header-anchor" href="#next-chapter" aria-label="Permalink to &quot;Next Chapter&quot;">​</a></h2><p><a href="./40-tabs.html"><strong>Chapter 40 — Tabs</strong></a></p><p>Organize your workflow with Vim tabs.</p>',26)])])}const p=e(a,[["render",i]]);export{m as __pageData,p as default};
